def gen(rng, size):
    def num(n):
        ds = [rng.randint(0, 9) for _ in range(n)]
        if n > 1 and ds[-1] == 0:
            ds[-1] = rng.randint(1, 9)
        return ds
    n1 = rng.randint(1, max(1, min(size, 100)))
    n2 = rng.randint(1, max(1, min(size, 100)))
    return [num(n1), num(n2)]

