class Solution:
    def addTwoNumbers(self, l1, l2):
        def to_int(node):
            digits = []
            while node:
                digits.append(node.val)
                node = node.next
            total = 0
            for d in reversed(digits):
                total = total * 10 + d
            return total
        s = to_int(l1) + to_int(l2)
        rev = [int(c) for c in str(s)][::-1]
        head = None
        for v in reversed(rev):
            head = ListNode(v, head)
        return head

